-- W1.6 questions batch 419/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00610', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X1年1月1日購買一台新設備定價$5,700,000，付款條件2/10，n/30，甲公司1月16日才以 現金支付價款。該新設備預計可用5年，殘值則為$186,000。甲公司預計未來5年內每年扣除折舊及 所得稅前之淨利均為$2,580,000，所得稅稅率為25%，流通在外普通股股數均為555,000股。若甲公 司對設備之後續衡量採成本模式並以年數合計法來提列折舊，則甲公司預估X5年的每股盈餘為何？', '["$2.99", "$3", "$3.98", "$4"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00611', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於 X1 年以$1,000,000 承包一建造合約，預計 3 年完工。其合約義務為隨時間經過逐步履 約者，該合約之結果無法可靠估計，但各期預期發生的合約成本很有可能回收。有關該工程的相 關資料為：X1年度投入工程成本$450,000，並估計至完工尚須投入成本$600,000；X2年度投入工 程成本$300,000，並估計至完工尚須投入成本$400,000；X3 年度投入工程成本$350,000。請問該 工程對甲公司X1年、X2年與X3年本期淨利之影響分別為何？', '["$0、$0與減少$100,000", "減少$50,000、減少$100,000與$0", "減少$50,000、減少$100,000與增加$50,000", "$0、減少$100,000與$0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00612', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司成立於X3年初，X3年分期付款銷貨收入為$360,000，認列銷貨毛利$72,000，X3年底產 品保固負債準備餘額為$180,000、應收分期銷貨帳款餘額為$210,000。除上述項目外，無其他會計 利潤與課稅所得間的差異存在，稅率17%，試問X3年底丙公司資產負債表上如何列示遞延所得 稅相關科目（若可互抵表達）？', '["流動資產下遞延所得稅資產$30,600", "非流動資產下遞延所得稅資產$23,460", "非流動負債下遞延所得稅負債$5,100", "流動負債下遞延所得稅負債$7,140"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00613', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '下列關於租賃之敘述，何者錯誤？', '["對承租人而言，屬於短期租賃或低價值標的資產之租賃，得選擇將租賃給付認列為租金費用之 會計處理", "若承租人擬將所承租之低價值標的資產進行轉租，不得選擇將租賃給付認列為租金費用之會計 處理", "承租人所發生與租賃安排有關之增額且直接可歸屬之支出，應列為租賃負債減少，並調整租賃 有效利率", "非製造商或經銷商出租人所發生與融資租賃安排有關之增額且直接可歸屬之支出，應列為租賃 投資淨額之增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00614', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司採曆年制，通常於次年度之 3 月 31 日發放前一年度之績效獎金給仍在職之員工。績效獎 金係依當年度獎金前利潤之4%至6%，以現金支付給全年在公司服務之員工，並於每年12月31 日決定每位員工所應得之績效獎金。若員工於次年度 3 月 31 日前離職，該員工將無法取得其績 效獎金，且甲公司不會對於該員工所喪失之績效獎金進行重新分配給其他員工。甲公司 X2 年 2 月董事會估計X2年1月1日至3月31日間將有3%員工離職，並決議按X1年年度獎金前利潤 之5%給付前述員工酬勞。X1年底甲公司考慮獎金前之利潤為$10,000,000，則X1年12月31日 應認列之員工獎金為何？', '["$388,000", "$400,000", "$485,000", "$500,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "14c4d6a3c3cc", "answer_pdf_sha1": "c80af91f6b7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00615', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲將其所有價值500 萬元之 A屋供乙設定普通抵押權，以擔保乙對甲之
200 萬元債權。其後，甲將設定有上述抵押權之A屋，以 300萬元出賣
予丙。未料於甲應交付 A屋予丙、並為移轉登記之履行期屆至前，因鄰
居丁處發生火災，致 A 屋遭延燒而滅失（A 屋滅失時之價值為 600 萬
元），甲乃基於侵權行為之規定，請求丁賠償甲因此所受損害。試問：乙、
丙就甲對丁所取得之損害賠償請求權，各得為如何之主張？乙、丙對甲
所取得之權利的主張其優劣次序如何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00616', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲死亡後，其遺產由其配偶乙及子女丙、丁繼承。遺產中之不動產部分，
於辦妥繼承登記後，基於乙之請求，與丙、丁達成協議各自分得部分，
但卻遲未基於該協議辦理分割登記。事經二十年後，丁因病死亡，其遺
產由戊繼承。戊乃請求乙、丙依與丁之前述協議，偕同出面辦理分割登
記，詎料戊之請求遭丙拒絕。丙之拒絕是否有理？戊有無得打破此僵局
之救濟方法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00617', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲欲透過email贈與乙A書，甲寫妥該封email後，於傳送前，甲因臨時有急事外出而未送出， 後其同居之友人丙借用其電腦，順手將該封信傳送出去。下列敘述，何者正確？', '["甲贈與乙A書之意思表示於email寫妥時，視為已發出", "甲贈與乙A書之意思表示於丙傳送到乙時發生效力", "甲得撤銷該贈與A書之意思表示", "甲應對乙之信賴利益損害，負賠償之責"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00618', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於暴利行為之敘述，何者錯誤？', '["行為人須有利用他人之急迫、輕率或無經驗而為法律行為者，此為暴利行為成立之主觀要件", "法律行為須有使他人為財產上之給付或為給付之約定，依當時情形顯失公平者，此為暴利行為 成立之客觀要件", "法律行為為暴利行為時，當事人得以意思表示行使撤銷權", "撤銷暴利之法律行為，及於債權行為與物權行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00619', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何種給付請求權，無5年短期消滅時效規定之適用？', '["利息給付請求權", "分期付價買賣之價金給付請求權", "退職金給付請求權", "贍養費給付請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
